sql:
SELECT image_path
FROM chart_images
WHERE chart_id = 0;

SELECT chart_id
FROM charts
WHERE query_id = (SELECT query_id FROM queries WHERE query_name = '{example query}');

SELECT DISTINCT chart_id 
FROM chart_sharing 
WHERE shared_with = 'group1';

SELECT COUNT(chart_id) 
  FROM chart_sharing 
  WHERE shared_with = 'group1';

SELECT chart_id
  FROM chart_feedback
  WHERE rating = (SELECT MAX(rating) FROM chart_feedback);

external_knowledge:
- The term 'specific user' refers to the user with a user_id of 1; 
- 'particular query' refers to the query with the name '{Query Name}'; 
- 'details of the chart' encompass its ID, chart type, title, x-axis label, y-axis label, series name, and the date it was commented on.

sql:
SELECT COUNT(*) 
FROM chart_feedback 
WHERE rating = 5 AND user_id = 0;

SELECT COUNT(DISTINCT chart_id)
FROM user_charts
WHERE user_id = 1;

SELECT MAX(tag_count) AS highest_tag_count
FROM (
  SELECT COUNT(*) AS tag_count
  FROM chart_tags
  GROUP BY chart_id
);
